141	// encodeEventsForExtra mirrors the in-memory shape AppendEvent already uses
142	// when storing events inline so that round-trips between attachment and inline
143	// produce identical JSON.
144	func encodeEventsForExtra(events []BeadEvent) []map[string]any {
145		out := make([]map[string]any, 0, len(events))
146		for _, e := range events {
147			out = append(out, map[string]any{
148				"kind":       e.Kind,
149				"summary":    e.Summary,
150				"body":       e.Body,
151				"actor":      e.Actor,
152				"created_at": e.CreatedAt,
153				"source":     e.Source,
154			})
155		}
156		return out
157	}
