217	func (w *ExecuteBeadWorker) handlePostAttemptDecomposition(ctx context.Context, candidate *bead.Bead, runtime ExecuteBeadLoopRuntime, assignee string, rcfg config.ResolvedConfig, at time.Time) {
218		emit := func(kind string, body map[string]any) {
219			if runtime.EventSink == nil {
220				return
221			}
222			data, _ := json.Marshal(map[string]any{"event": kind, "payload": body})
223			_, _ = fmt.Fprintf(runtime.EventSink, "%s\n", data)
224		}
225		parkOperator := func(reason string) {
226			if runtime.Log != nil {
227				_, _ = fmt.Fprintf(runtime.Log, "post-attempt decomposition blocked: %s (%s)\n", reason, candidate.ID)
228			}
229			emit("post_attempt_decomposition.blocked", map[string]any{
230				"bead_id": candidate.ID,
231				"reason":  reason,
232			})
233			if berr := parkBeadPostIntakeRejection(w.Store, candidate.ID, assignee, PreClaimIntakeOperatorRequired, reason, at); berr != nil && runtime.Log != nil {
