235			}
236		}
237	
238		// Queue-level depth check: orchestrator uses its own cap, not the
239		// implementation prompt's hardcoded depth-2 cap.
240		maxDepth := rcfg.MaxDecompositionDepth()
241		if maxDepth > 0 && storeBeadDepth(w.Store, candidate) >= maxDepth {
242			overflowBody, _ := json.Marshal(map[string]any{
243				"depth": storeBeadDepth(w.Store, candidate),
244				"max":   maxDepth,
245			})
246			_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
247				Kind:      "triage-overflow",
248				Summary:   "depth cap exceeded during post-attempt decomposition",
249				Body:      string(overflowBody),
250				Actor:     assignee,
251				Source:    "ddx agent execute-loop",
252				CreatedAt: at,
253			})
254			parkOperator("queue-level depth cap exceeded; operator must split")
255			return
256		}
