251	func truncateTier(s string, max int) string {
252		if len(s) <= max {
253			return s
254		}
255		const ellipsis = "…"
256		if max <= len(ellipsis) {
257			return strings.Repeat(".", max)
258		}
259		return s[:max-len(ellipsis)] + ellipsis
260	}
