328	// reviewVerdictCategory normalises a kind:review event summary into one of
329	// "approve", "approve_with_edits", "reject", or "" when it cannot be
330	// classified. Matching is case-insensitive and tolerates the canonical
331	// verdict names used by the reviewer (APPROVE / REQUEST_CHANGES / BLOCK)
332	// as well as their generic equivalents.
333	func reviewVerdictCategory(summary string) string {
334		s := strings.ToUpper(strings.TrimSpace(summary))
335		switch s {
336		case "APPROVE":
337			return "approve"
338		case "APPROVE_WITH_EDITS", "REQUEST_CHANGES":
339			return "approve_with_edits"
340		case "REJECT", "BLOCK":
341			return "reject"
342		}
343		return ""
344	}
