346	// computeReviewOutcomesReport scans every bead in workingDir/.ddx and
347	// produces the FEAT-022 §17 review-outcomes report:
348	//   - per-tier verdict aggregates (Rows): each kind:review event is
349	//     attributed to the most recent kind:routing event that precedes it on
350	//     the same bead. Reviews on beads without any preceding routing event
351	//     are bucketed under an "unknown" tier.
352	//   - prompt-size quantiles (P50/P95/P99) computed over input_bytes parsed
353	//     from the canonical event-body summary on every kind:review,
354	//     review-error, and review-manual-required event.
355	//   - failure_classes: counts of context_overflow, provider_empty,
356	//     unparseable, and transport from review-error and review-manual-required
357	//     events. All four keys are always present (zero-valued when unobserved)
358	//     so downstream `jq -e 'has(...)'` consumers are stable.
359	//
360	// When window > 0, events whose CreatedAt is older than now-window are
361	// ignored. now is the reference time the window is measured from; pass
362	// time.Time{} (zero) to disable windowing regardless of the window value.
363	func computeReviewOutcomesReport(workingDir string, window time.Duration, now time.Time) (reviewOutcomesReport, error) {
364		store := bead.NewStore(filepath.Join(workingDir, ".ddx"))
365		beads, err := store.ReadAll()
366		if err != nil {
367			return reviewOutcomesReport{}, fmt.Errorf("read beads: %w", err)
368		}
369	
370		type agg struct {
371			harness    string
372			model      string
373			reviews    int
374			approvals  int
375			rejections int
376		}
377		byTier := map[string]*agg{}
378		order := []string{}
379	
380		failureClasses := map[string]int{}
381		for _, c := range reviewFailureClasses {
382			failureClasses[c] = 0
383		}
384		var promptSizes []int
385	
386		var cutoff time.Time
387		hasCutoff := window > 0 && !now.IsZero()
388		if hasCutoff {
389			cutoff = now.Add(-window)
390		}
391	
392		for _, b := range beads {
393			events, err := store.Events(b.ID)
394			if err != nil {
395				return reviewOutcomesReport{}, fmt.Errorf("read events for %s: %w", b.ID, err)
396			}
397			// Walk events in chronological order, tracking the most recent
398			// routing decision so each review is attributed to the tier that
399			// produced the work under review.
400			sort.SliceStable(events, func(i, j int) bool {
401				return events[i].CreatedAt.Before(events[j].CreatedAt)
402			})
403	
404			var curHarness, curModel string
405			haveRouting := false
406			for _, e := range events {
407				if hasCutoff && !e.CreatedAt.IsZero() && e.CreatedAt.Before(cutoff) {
408					// Routing events outside the window still update tier
409					// attribution context for in-window reviews on the same
410					// bead — quantiles and class counts are window-scoped, but
411					// per-tier attribution should reflect the most recent
412					// routing decision known at review time.
413					if e.Kind == "routing" {
414						if h, m, ok := parseRoutingHarnessModel(e); ok {
415							curHarness = h
416							curModel = m
417							haveRouting = true
418						}
419					}
420					continue
421				}
422				switch e.Kind {
423				case "routing":
424					if h, m, ok := parseRoutingHarnessModel(e); ok {
425						curHarness = h
426						curModel = m
427						haveRouting = true
428					}
429				case "review":
430					if size, ok := parseInputBytesFromBody(e.Body); ok {
431						promptSizes = append(promptSizes, size)
432					}
433					cat := reviewVerdictCategory(e.Summary)
434					if cat == "" {
435						continue
436					}
437					harness, model := curHarness, curModel
438					if !haveRouting {
439						harness, model = "unknown", ""
440					}
441					tier := tierKey(harness, model)
442					a, ok := byTier[tier]
443					if !ok {
444						a = &agg{harness: harness, model: model}
445						byTier[tier] = a
446						order = append(order, tier)
447					}
448					a.reviews++
449					switch cat {
450					case "approve":
451						a.approvals++
452					case "approve_with_edits", "reject":
453						a.rejections++
454					}
455				case "review-error", "review-manual-required":
456					if size, ok := parseInputBytesFromBody(e.Body); ok {
457						promptSizes = append(promptSizes, size)
458					}
459					class := strings.TrimSpace(e.Summary)
460					if _, known := failureClasses[class]; known {
461						failureClasses[class]++
462					}
463				}
464			}
465		}
466	
467		rows := make([]reviewOutcomesRow, 0, len(order))
468		for _, tier := range order {
469			a := byTier[tier]
470			row := reviewOutcomesRow{
471				Tier:       tier,
472				Harness:    a.harness,
473				Model:      a.model,
474				Reviews:    a.reviews,
475				Approvals:  a.approvals,
476				Rejections: a.rejections,
477			}
478			if a.reviews > 0 {
479				row.ApprovalRate = float64(a.approvals) / float64(a.reviews)
480			}
481			rows = append(rows, row)
482		}
483		sort.Slice(rows, func(i, j int) bool { return rows[i].Tier < rows[j].Tier })
484	
485		return reviewOutcomesReport{
486			Rows:           rows,
487			PromptSizeP50:  quantile(promptSizes, 0.50),
488			PromptSizeP95:  quantile(promptSizes, 0.95),
489			PromptSizeP99:  quantile(promptSizes, 0.99),
490			FailureClasses: failureClasses,
491		}, nil
492	}
