494	// reInputBytesField extracts the input_bytes value emitted by
495	// formatEventBodySummary into review/review-error/review-manual-required
496	// event bodies.
497	var reInputBytesField = regexp.MustCompile(`(?m)^input_bytes=(\d+)\s*$`)
