499	// parseInputBytesFromBody returns the input_bytes value carried by an event
500	// body's canonical summary line. ok=false when the line is absent or
501	// malformed.
502	func parseInputBytesFromBody(body string) (int, bool) {
503		m := reInputBytesField.FindStringSubmatch(body)
504		if m == nil {
505			return 0, false
