514	// quantile returns the integer-rounded q-th quantile of values using the
515	// nearest-rank method. Returns 0 for an empty slice so the metrics surface
516	// is always serialisable. q is clamped to [0,1].
517	func quantile(values []int, q float64) int {
518		if len(values) == 0 {
519			return 0
520		}
521		if q < 0 {
522			q = 0
523		}
524		if q > 1 {
525			q = 1
526		}
527		sorted := make([]int, len(values))
528		copy(sorted, values)
529		sort.Ints(sorted)
530		// Nearest-rank: rank = ceil(q * N), 1-indexed.
531		rank := int(math.Ceil(q * float64(len(sorted))))
532		if rank < 1 {
533			rank = 1
534		}
535		if rank > len(sorted) {
536			rank = len(sorted)
537		}
538		return sorted[rank-1]
539	}
