641	// computeCostEfficiency scans .ddx/executions/*/result.json under workingDir
642	// and aggregates per-bead cost totals. When lastN > 0, the set of beads in
643	// the output is restricted to those with at least one attempt in the most
644	// recent N executions; for those beads, *all* historical attempts contribute
645	// to the totals so escalation chains are not artificially truncated.
646	func computeCostEfficiency(workingDir string, lastN int) ([]costEfficiencyRow, error) {
647		execRoot := filepath.Join(workingDir, ".ddx", "executions")
648		entries, err := os.ReadDir(execRoot)
649		if err != nil {
650			if os.IsNotExist(err) {
651				return []costEfficiencyRow{}, nil
652			}
653			return nil, fmt.Errorf("read executions dir: %w", err)
654		}
655	
656		names := make([]string, 0, len(entries))
657		for _, entry := range entries {
658			if entry.IsDir() {
659				names = append(names, entry.Name())
660			}
661		}
662		sort.Strings(names)
663	
664		type loadedAttempt struct {
665			beadID  string
666			harness string
667			model   string
668			outcome string
669			costUSD float64
670		}
671		loaded := make([]loadedAttempt, 0, len(names))
672		for _, name := range names {
673			resultPath := filepath.Join(execRoot, name, "result.json")
674			raw, err := os.ReadFile(resultPath)
675			if err != nil {
676				continue
677			}
678			var res agent.ExecuteBeadResult
679			if err := json.Unmarshal(raw, &res); err != nil {
680				continue
681			}
682			if res.BeadID == "" {
683				continue
684			}
685			loaded = append(loaded, loadedAttempt{
686				beadID:  res.BeadID,
687				harness: res.Harness,
688				model:   res.Model,
689				outcome: res.Outcome,
690				costUSD: res.CostUSD,
691			})
692		}
693	
694		// --last N: restrict the output set to beads touched by the most recent
695		// N usable attempts. All historical attempts for those beads still
696		// contribute to totals so escalation cost is visible.
697		var includeBead map[string]bool
698		if lastN > 0 && len(loaded) > 0 {
699			includeBead = map[string]bool{}
700			start := len(loaded) - lastN
701			if start < 0 {
702				start = 0
703			}
704			for _, a := range loaded[start:] {
705				includeBead[a.beadID] = true
706			}
707		}
708	
709		type agg struct {
710			beadID            string
711			totalAttempts     int
712			totalCostUSD      float64
713			successfulCostUSD float64
714			wastedCostUSD     float64
715			finalHarness      string
716			finalModel        string
717		}
718		byBead := map[string]*agg{}
719		order := []string{}
720	
721		for _, a := range loaded {
722			if includeBead != nil && !includeBead[a.beadID] {
723				continue
724			}
725			g, ok := byBead[a.beadID]
726			if !ok {
727				g = &agg{beadID: a.beadID}
728				byBead[a.beadID] = g
729				order = append(order, a.beadID)
730			}
731			g.totalAttempts++
732			g.totalCostUSD += a.costUSD
733			if a.outcome == "task_succeeded" {
734				g.successfulCostUSD += a.costUSD
735			} else {
736				g.wastedCostUSD += a.costUSD
737			}
738			// Attempts iterate in chronological order, so the last assignment
739			// wins — that is the most recent tier tried on this bead.
740			g.finalHarness = a.harness
741			g.finalModel = a.model
742		}
743	
744		rows := make([]costEfficiencyRow, 0, len(order))
745		for _, id := range order {
746			g := byBead[id]
747			rows = append(rows, costEfficiencyRow{
748				BeadID:            g.beadID,
749				TotalAttempts:     g.totalAttempts,
750				TotalCostUSD:      g.totalCostUSD,
751				SuccessfulCostUSD: g.successfulCostUSD,
752				WastedCostUSD:     g.wastedCostUSD,
753				FinalTier:         tierKey(g.finalHarness, g.finalModel),
754				FinalHarness:      g.finalHarness,
755			})
756		}
757		sort.Slice(rows, func(i, j int) bool { return rows[i].BeadID < rows[j].BeadID })
758		return rows, nil
759	}
