763		fmt.Fprintf(out, "%-24s  %14s  %14s  %18s  %14s  %-30s  %s\n",
764			"BEAD_ID", "TOTAL_ATTEMPTS", "TOTAL_COST_USD", "SUCCESSFUL_COST_USD", "WASTED_COST_USD", "FINAL_TIER", "FINAL_HARNESS")
765		for _, r := range rows {
