33	// scanBeadMetrics reads .ddx/executions/*/result.json under workingDir and
34	// groups attempts by bead_id. Malformed or bead_id-less results are skipped.
35	func scanBeadMetrics(workingDir string) (map[string]*beadMetricsSummary, error) {
36		execRoot := filepath.Join(workingDir, ".ddx", "executions")
37		entries, err := os.ReadDir(execRoot)
38		if err != nil {
39			if os.IsNotExist(err) {
40				return map[string]*beadMetricsSummary{}, nil
41			}
42			return nil, fmt.Errorf("read executions dir: %w", err)
43		}
44	
45		type agg struct {
46			attempts   int
47			tokens     int
48			cost       float64
49			totalDurMS float64
50		}
51		byBead := map[string]*agg{}
52	
53		for _, entry := range entries {
54			if !entry.IsDir() {
55				continue
56			}
57			resultPath := filepath.Join(execRoot, entry.Name(), "result.json")
58			raw, err := os.ReadFile(resultPath)
59			if err != nil {
60				continue
61			}
62			var res agent.ExecuteBeadResult
63			if err := json.Unmarshal(raw, &res); err != nil {
64				continue
65			}
66			if res.BeadID == "" {
67				continue
68			}
69			a, ok := byBead[res.BeadID]
70			if !ok {
71				a = &agg{}
72				byBead[res.BeadID] = a
73			}
74			a.attempts++
75			a.tokens += res.Tokens
76			a.cost += res.CostUSD
77			a.totalDurMS += float64(res.DurationMS)
78		}
79	
80		out := make(map[string]*beadMetricsSummary, len(byBead))
81		for id, a := range byBead {
82			s := &beadMetricsSummary{
83				AttemptCount: a.attempts,
84				TotalTokens:  a.tokens,
85				TotalCostUSD: a.cost,
86			}
87			if a.attempts > 0 {
88				s.AvgDurationMS = a.totalDurMS / float64(a.attempts)
89			}
90			out[id] = s
91		}
92		return out, nil
93	}
