95	// beadMetricsFor returns the aggregate metrics for a single bead, or nil when
96	// no execution evidence exists.
97	func beadMetricsFor(workingDir, beadID string) (*beadMetricsSummary, error) {
98		all, err := scanBeadMetrics(workingDir)
99		if err != nil {
100			return nil, err
101		}
102		return all[beadID], nil
103	}
